await page.goto('/baggage');
const dropZone = page.getByTestId('baggage-drop-zone');
await page.locator('[draggable="true"]').filter({ hasText: 'Carry-on (1 piece)' }).dragTo(dropZone);
await page.locator('[draggable="true"]').filter({ hasText: 'Checked bag (1 piece)' }).dragTo(dropZone);
await dropZone.getByRole('button', { name: 'Remove' }).first().click();
await expect(dropZone.getByText('Checked bag (1 piece)')).toBeVisible();
await expect(dropZone.getByText('Carry-on (1 piece)')).not.toBeVisible();
